import React, { useState, useCallback, useMemo } from 'react';
import { AppStatus, DocumentKey, VerificationState } from './types';
import Header from './components/Header';
import ProgressBar from './components/ProgressBar';
import KycCard from './components/KycCard';
import SuccessView from './components/SuccessView';
import PrivacyNotice from './components/PrivacyNotice';

const App: React.FC = () => {
  const [status, setStatus] = useState<AppStatus>(AppStatus.UPLOADING_PHASE);
  const [state, setState] = useState<VerificationState>({
    front: { file: null, previewUrl: null, error: null },
    back: { file: null, previewUrl: null, error: null },
    residence: { file: null, previewUrl: null, error: null },
  });

  const handleFileChange = useCallback((key: DocumentKey, file: File | null) => {
    if (!file) {
      setState(prev => ({
        ...prev,
        [key]: { file: null, previewUrl: null, error: null }
      }));
      return;
    }

    const validTypes = ['image/jpeg', 'image/jpg', 'image/png'];
    const maxSize = 10 * 1024 * 1024;

    let error = null;
    if (!validTypes.includes(file.type)) {
      error = 'Formato no permitido. Use JPG o PNG.';
    } else if (file.size > maxSize) {
      error = 'El archivo supera el límite de 10 MB.';
    }

    const previewUrl = error ? null : URL.createObjectURL(file);

    setState(prev => {
      if (prev[key].previewUrl) URL.revokeObjectURL(prev[key].previewUrl!);
      return {
        ...prev,
        [key]: { file: error ? null : file, previewUrl, error }
      };
    });
  }, []);

  const isComplete = useMemo(() => {
    return !!(state.front.file && state.back.file && state.residence.file);
  }, [state]);

  /**
   * GUÍA DE CONEXIÓN:
   * 1. Reemplaza 'https://api.tu-servidor.com/kyc/upload' por tu URL real.
   * 2. Asegúrate de que tu servidor soporte CORS para recibir peticiones de este dominio.
   */
  const uploadToServer = async (data: VerificationState) => {
    const formData = new FormData();

    // Agregamos los archivos al FormData
    if (data.front.file) formData.append('id_front', data.front.file);
    if (data.back.file) formData.append('id_back', data.back.file);
    if (data.residence.file) formData.append('proof_residence', data.residence.file);

    // Opcional: Agregar datos del usuario si los tuvieras
    // formData.append('user_id', '12345');

    try {
      const response = await fetch('https://api.tu-servidor.com/kyc/upload', {
        method: 'POST',
        body: formData,
        // No establezcas 'Content-Type', el navegador lo hará automáticamente por el FormData
      });

      if (!response.ok) throw new Error('Error en la respuesta del servidor');

      return await response.json();
    } catch (error) {
      console.error('Error subiendo archivos:', error);
      // Para propósitos de demo, si falla la URL inexistente, simulamos éxito tras 2 segundos
      await new Promise(resolve => setTimeout(resolve, 2000));
    }
  };

  const handleSubmit = async () => {
    if (!isComplete) return;
    setStatus(AppStatus.SUBMITTING);

    try {
      await uploadToServer(state);
      setStatus(AppStatus.SUCCESS);
      setState({
        front: { file: null, previewUrl: null, error: null },
        back: { file: null, previewUrl: null, error: null },
        residence: { file: null, previewUrl: null, error: null },
      });
    } catch (err) {
      alert('Error al enviar los documentos. Inténtelo de nuevo.');
      setStatus(AppStatus.UPLOADING_PHASE);
    }
  };

  const currentProgressStep = useMemo(() => {
    if (status === AppStatus.SUCCESS) return 4;
    if (state.residence.file) return 3;
    if (state.back.file) return 2;
    if (state.front.file) return 1;
    return 0;
  }, [state, status]);

  if (status === AppStatus.SUCCESS) {
    return <SuccessView onReset={() => setStatus(AppStatus.UPLOADING_PHASE)} />;
  }

  return (
    <div className="min-h-screen bg-gray-50 pb-12 transition-all duration-300">
      <Header />
      <main className="max-w-xl mx-auto px-4 mt-8">
        <ProgressBar currentStep={currentProgressStep} />
        <div className="space-y-6 mt-8">
          <KycCard title="Documento de Identidad – Frente" description="Asegúrese de que el nombre y la foto sean visibles." docKey="front" info={state.front} onFileChange={handleFileChange} disabled={status === AppStatus.SUBMITTING} />
          <KycCard title="Documento de Identidad – Reverso" description="Capture la parte posterior con todos los códigos legibles." docKey="back" info={state.back} onFileChange={handleFileChange} disabled={status === AppStatus.SUBMITTING} />
          <KycCard title="Comprobante de Residencia" description="Recibo de servicio público no mayor a 3 meses." docKey="residence" info={state.residence} onFileChange={handleFileChange} disabled={status === AppStatus.SUBMITTING} />
        </div>
        <button onClick={handleSubmit} disabled={!isComplete || status === AppStatus.SUBMITTING} className={`w-full mt-10 py-4 rounded-xl font-bold text-lg transition-all transform active:scale-95 flex items-center justify-center gap-3 ${isComplete && status !== AppStatus.SUBMITTING ? 'bg-[#ceff04] text-[#1d1c2d] shadow-lg hover:shadow-xl hover:bg-[#dfff00]' : 'bg-gray-200 text-gray-400 cursor-not-allowed'}`}>
          {status === AppStatus.SUBMITTING ? (<><div className="w-5 h-5 border-2 border-navy border-t-transparent rounded-full animate-spin"></div>Enviando...</>) : ('Enviar verificación')}
        </button>
        <PrivacyNotice />
      </main>
    </div>
  );
};

export default App;

// PEGA AQUÍ LOS DATOS QUE COPIASTE EN EL PASO 2
export const firebaseConfig = {
  apiKey: "TU_API_KEY",
  authDomain: "TU_PROYECTO.firebaseapp.com",
  projectId: "TU_PROYECTO",
  storageBucket: "TU_PROYECTO.appspot.com",
  messagingSenderId: "TU_ID",
  appId: "TU_APP_ID"
};

import React, { useState, useCallback, useMemo } from 'react';
import { AppStatus, DocumentKey, VerificationState } from './types';
import Header from './components/Header';
import ProgressBar from './components/ProgressBar';
import KycCard from './components/KycCard';
import SuccessView from './components/SuccessView';
import PrivacyNotice from './components/PrivacyNotice';

// Herramientas de Firebase
import { initializeApp } from 'firebase/app';
import { getStorage, ref, uploadBytes, getDownloadURL } from 'firebase/storage';
import { getFirestore, collection, addDoc, serverTimestamp } from 'firebase/firestore';
import { firebaseConfig } from './firebaseConfig';

// Inicializamos la conexión con Google Firebase
const app = initializeApp(firebaseConfig);
const storage = getStorage(app);
const db = getFirestore(app);

const App: React.FC = () => {
  const [status, setStatus] = useState<AppStatus>(AppStatus.UPLOADING_PHASE);
  const [state, setState] = useState<VerificationState>({
    front: { file: null, previewUrl: null, error: null },
    back: { file: null, previewUrl: null, error: null },
    residence: { file: null, previewUrl: null, error: null },
  });

  const handleFileChange = useCallback((key: DocumentKey, file: File | null) => {
    if (!file) {
      setState(prev => ({
        ...prev,
        [key]: { file: null, previewUrl: null, error: null }
      }));
      return;
    }

    const validTypes = ['image/jpeg', 'image/jpg', 'image/png'];
    const maxSize = 10 * 1024 * 1024;

    let error = null;
    if (!validTypes.includes(file.type)) {
      error = 'Formato no permitido. Use JPG o PNG.';
    } else if (file.size > maxSize) {
      error = 'El archivo supera el límite de 10 MB.';
    }

    const previewUrl = error ? null : URL.createObjectURL(file);

    setState(prev => {
      if (prev[key].previewUrl) URL.revokeObjectURL(prev[key].previewUrl!);
      return {
        ...prev,
        [key]: { file: error ? null : file, previewUrl, error }
      };
    });
  }, []);

  const isComplete = useMemo(() => {
    return !!(state.front.file && state.back.file && state.residence.file);
  }, [state]);

  /**
   * PROCESO DE SUBIDA A FIREBASE:
   * 1. Sube cada imagen al "Storage" y obtiene una URL pública.
   * 2. Guarda los datos finales en una colección de "Firestore" llamada 'verificaciones'.
   */
  const uploadToFirebase = async (data: VerificationState) => {
    // Generamos un ID único para esta carpeta (puedes usar el email del usuario en el futuro)
    const folderId = `kyc_${Date.now()}`;
    const urls: Record<string, string> = {};

    // 1. Subir archivos al Storage
    const uploadTasks = Object.entries(data).map(async ([key, info]) => {
      if (!info.file) return;

      // Creamos una referencia/ruta en la nube
      const storageRef = ref(storage, `kyc_documents/${folderId}/${key}_${info.file.name}`);

      // Subimos el archivo
      const snapshot = await uploadBytes(storageRef, info.file);

      // Obtenemos el link de descarga
      const downloadUrl = await getDownloadURL(snapshot.ref);
      urls[key] = downloadUrl;
    });

    await Promise.all(uploadTasks);

    // 2. Guardar registro en la Base de Datos (Firestore)
    await addDoc(collection(db, 'verificaciones'), {
      folderId,
      documentUrls: urls,
      status: 'PENDIENTE_REVISION',
      createdAt: serverTimestamp(),
    });

    return true;
  };

  const handleSubmit = async () => {
    if (!isComplete) return;

    // Si olvidaste configurar las claves, avisamos
    if (firebaseConfig.apiKey === "TU_API_KEY") {
      alert("Error: Debes configurar tus claves de Firebase en el archivo firebaseConfig.ts");
      return;
    }

    setStatus(AppStatus.SUBMITTING);

    try {
      await uploadToFirebase(state);
      setStatus(AppStatus.SUCCESS);

      // Limpiamos todo
      setState({
        front: { file: null, previewUrl: null, error: null },
        back: { file: null, previewUrl: null, error: null },
        residence: { file: null, previewUrl: null, error: null },
      });
    } catch (err) {
      console.error(err);
      alert('Error al conectar con Google Firebase. Revisa tu conexión o configuración.');
      setStatus(AppStatus.UPLOADING_PHASE);
    }
  };

  const currentProgressStep = useMemo(() => {
    if (status === AppStatus.SUCCESS) return 4;
    if (state.residence.file) return 3;
    if (state.back.file) return 2;
    if (state.front.file) return 1;
    return 0;
  }, [state, status]);

  if (status === AppStatus.SUCCESS) {
    return <SuccessView onReset={() => setStatus(AppStatus.UPLOADING_PHASE)} />;
  }

  return (
