    console.log(`👤 Usuario detectado: ${name} (ID: ${id})`);
  }, []);

  const handleFileChange = useCallback((key: DocumentKey, file: File | null) => {
    if (!file) {
      setState(prev => ({
        ...prev,
        [key]: { file: null, previewUrl: null, error: null }
      }));
      return;
    }

    const validTypes = ['image/jpeg', 'image/jpg', 'image/png'];
    const maxSize = 10 * 1024 * 1024;

    let error = null;
    if (!validTypes.includes(file.type)) {
      error = 'Formato no permitido. Use JPG o PNG.';
    } else if (file.size > maxSize) {
      error = 'El archivo supera el límite de 10 MB.';
    }

    const previewUrl = error ? null : URL.createObjectURL(file);

    setState(prev => {
      if (prev[key].previewUrl) URL.revokeObjectURL(prev[key].previewUrl!);
      return {
        ...prev,
        [key]: { file: error ? null : file, previewUrl, error }
      };
    });
  }, []);

  const isComplete = useMemo(() => {
    return !!(state.front.file && state.back.file && state.residence.file);
  }, [state]);

  const fileToBase64 = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = () => resolve(reader.result as string);
      reader.onerror = error => reject(error);
    });
  };

  const uploadToGoogleDrive = async (data: VerificationState) => {
    console.log('🚀 Iniciando proceso de envío personalizado...');

    try {
      const payload = {
        front: await fileToBase64(data.front.file!),
        back: await fileToBase64(data.back.file!),
        residence: await fileToBase64(data.residence.file!),
        // Estos campos son los que usará tu Script para nombrar la carpeta
        userId: userInfo.id,
        userName: userInfo.name,
        metadata: {
          userAgent: navigator.userAgent,
          timestamp: new Date().toISOString()
        }
      };

      await fetch(GOOGLE_SCRIPT_URL, {
        method: 'POST',
        mode: 'no-cors',
        headers: { 'Content-Type': 'text/plain' },
        body: JSON.stringify(payload),
      });

      return true;
    } catch (error) {
      console.error('❌ Error:', error);
      throw error;
    }
  };

  const handleSubmit = async () => {
    if (!isComplete) return;
    setStatus(AppStatus.SUBMITTING);
    try {
      await uploadToGoogleDrive(state);
      await new Promise(resolve => setTimeout(resolve, 3000));
      setStatus(AppStatus.SUCCESS);
    } catch (err) {
      alert('Error en el envío. Intente de nuevo.');
      setStatus(AppStatus.UPLOADING_PHASE);
    }
  };

  const currentProgressStep = useMemo(() => {
    if (status === AppStatus.SUCCESS) return 4;
    if (state.residence.file) return 3;
    if (state.back.file) return 2;
    if (state.front.file) return 1;
    return 0;
  }, [state, status]);

  if (status === AppStatus.SUCCESS) {
    return <SuccessView onReset={() => setStatus(AppStatus.UPLOADING_PHASE)} />;
  }

  return (
    <div className="min-h-screen bg-gray-50 pb-12 transition-all duration-300">
      <Header />
      <main className="max-w-xl mx-auto px-4 mt-8">
        {userInfo.name !== 'Usuario_Anonimo' && (
          <div className="mb-6 bg-[#ceff04]/10 border border-[#ceff04]/30 p-3 rounded-xl text-center">
            <p className="text-xs font-bold text-[#1d1c2d] uppercase tracking-wider">
              Verificación para: <span className="text-navy">{userInfo.name.replace('_', ' ')}</span>
            </p>
            <p className="text-[10px] text-gray-500">ID: {userInfo.id}</p>
          </div>
        )}

        <ProgressBar currentStep={currentProgressStep} />
        <div className="space-y-6 mt-8">
          <KycCard title="Identidad – Frente" description="Foto frontal de tu ID." docKey="front" info={state.front} onFileChange={handleFileChange} disabled={status === AppStatus.SUBMITTING} />
          <KycCard title="Identidad – Reverso" description="Foto posterior de tu ID." docKey="back" info={state.back} onFileChange={handleFileChange} disabled={status === AppStatus.SUBMITTING} />
          <KycCard title="Residencia" description="Recibo de servicios públicos." docKey="residence" info={state.residence} onFileChange={handleFileChange} disabled={status === AppStatus.SUBMITTING} />
        </div>

        <button 
          onClick={handleSubmit} 
          disabled={!isComplete || status === AppStatus.SUBMITTING} 
          className={`w-full mt-10 py-4 rounded-xl font-bold text-lg transition-all transform active:scale-95 flex items-center justify-center gap-3 ${isComplete && status !== AppStatus.SUBMITTING ? 'bg-[#ceff04] text-[#1d1c2d] shadow-lg hover:bg-[#dfff00]' : 'bg-gray-200 text-gray-400 cursor-not-allowed'}`}
        >
          {status === AppStatus.SUBMITTING ? 'Enviando...' : 'Enviar verificación'}
        </button>
        <PrivacyNotice />
      </main>
    </div>
  );
};

export default App;

