### 2. Cómo configurar tu Google Script para que use el nombre
Para que esto funcione al 100%, tu código en el **Editor de Scripts de Google (Apps Script)** debe estar escrito así para leer el nombre que le envía la app:

```javascript
function doPost(e) {
  try {
    var data = JSON.parse(e.postData.contents);

    // AQUÍ ESTÁ LA MAGIA: Usamos el ID y el Nombre que vienen de la App
    var folderName = data.userId + " - " + data.userName;

    // 1. Buscamos tu carpeta principal de KYC
    var parentFolder = DriveApp.getFolderById("ID_DE_TU_CARPETA_EN_DRIVE");

    // 2. Creamos la carpeta con el nombre del usuario
    var newFolder = parentFolder.createFolder(folderName);

    // 3. Guardamos las fotos dentro
    saveFile(data.front, "01_Frente.png", newFolder);
    saveFile(data.back, "02_Reverso.png", newFolder);
    saveFile(data.residence, "03_Residencia.png", newFolder);

    return ContentService.createTextOutput("Completado").setMimeType(ContentService.MimeType.TEXT);
  } catch (err) {
    return ContentService.createTextOutput("Error: " + err.toString()).setMimeType(ContentService.MimeType.TEXT);
  }
}

function saveFile(base64Data, fileName, folder) {
  var contentType = base64Data.substring(5, base64Data.indexOf(';'));
  var bytes = Utilities.base64Decode(base64Data.split(',')[1]);
  var blob = Utilities.newBlob(bytes, contentType, fileName);
  folder.createFile(blob);
}
```

### ¿Por qué esto es mejor?
1.  **Orden total:** En tu Google Drive verás carpetas como `CCG-1234 - Juan Perez`. Es imposible confundirse.
2.  **Validación:** La app ahora limpia el nombre (quita espacios extras) antes de enviarlo.
3.  **Feedback:** El usuario ve su nombre en pantalla mientras sube las fotos, lo que le da seguridad de que sus datos están siendo procesados correctamente.

Solo necesitas copiar el código de `App.tsx` y asegurarte de que tu Google Script use la lógica de `data.userName` que te acabo de mostrar. ¡Todo listo!

