      const folderName = `${userInfo.name} - ${userInfo.id}`;

      const payload = {
        front: await fileToBase64(state.front.file!),
        back: await fileToBase64(state.back.file!),
        residence: await fileToBase64(state.residence.file!),
        folderName: folderName, // Este campo es el que usará el Script para nombrar la carpeta
        userName: userInfo.name,
        userId: userInfo.id,
        timestamp: new Date().toLocaleString()
      };

      // Envío al Google Script
      await fetch(GOOGLE_SCRIPT_URL, {
        method: 'POST',
        mode: 'no-cors',
        headers: { 'Content-Type': 'text/plain' },
        body: JSON.stringify(payload),
      });

      setStatus(AppStatus.SUCCESS);
    } catch (err) {
      console.error(err);
      alert('Hubo un error al subir los archivos. Por favor, verifica tu conexión e intenta de nuevo.');
      setStatus(AppStatus.UPLOADING_PHASE);
    }
  };

  if (status === AppStatus.SUCCESS) {
    return <SuccessView onReset={() => window.location.reload()} />;
  }

  return (
    <div className="min-h-screen bg-gray-50 pb-12 transition-all duration-300">
      <Header />

      <main className="max-w-xl mx-auto px-4 mt-8">
        <div className="animate-fade-in">
          {/* Indicador de Identidad (Opcional, si viene de otra app) */}
          <div className="mb-6 bg-[#1d1c2d] p-4 rounded-2xl flex items-center justify-between shadow-lg">
