              </div>
              <div>
                <p className="text-[10px] text-gray-400 uppercase font-bold tracking-widest leading-none">Expediente</p>
                <p className="text-sm text-white font-bold">{userInfo.name}</p>
              </div>
            </div>
            <div className="text-right">
              <p className="text-[10px] text-gray-400 uppercase font-bold tracking-widest leading-none">ID Usuario</p>
              <p className="text-sm text-[#ceff04] font-mono font-bold">{userInfo.id}</p>
            </div>
          </div>

          <ProgressBar currentStep={status === AppStatus.UPLOADING_PHASE ? 2 : 4} />

          <div className="space-y-6 mt-8">
            <KycCard 
              title="Identidad – Frente" 
              description="Asegúrate de que los datos sean legibles y sin reflejos." 
              docKey="front" 
              info={state.front} 
              onFileChange={handleFileChange} 
              disabled={status === AppStatus.SUBMITTING} 
            />
            <KycCard 
              title="Identidad – Reverso" 
              description="Parte trasera de tu identificación oficial." 
              docKey="back" 
              info={state.back} 
              onFileChange={handleFileChange} 
              disabled={status === AppStatus.SUBMITTING} 
            />
            <KycCard 
              title="Comprobante de Domicilio" 
              description="Recibo de servicios (Luz, Agua, Teléfono) reciente." 
              docKey="residence" 
              info={state.residence} 
              onFileChange={handleFileChange} 
              disabled={status === AppStatus.SUBMITTING} 
            />
          </div>

          <button 
            onClick={handleSubmit} 
            disabled={!isComplete || status === AppStatus.SUBMITTING} 
            className={`w-full mt-10 py-5 rounded-2xl font-bold text-lg transition-all transform active:scale-95 flex items-center justify-center gap-3 shadow-xl ${isComplete && status !== AppStatus.SUBMITTING ? 'bg-[#ceff04] text-[#1d1c2d] hover:bg-[#dfff00] hover:-translate-y-1' : 'bg-gray-200 text-gray-400 cursor-not-allowed'}`}
          >
            {status === AppStatus.SUBMITTING ? (
              <>
                <div className="w-5 h-5 border-3 border-navy border-t-transparent rounded-full animate-spin"></div>
                Enviando a revisión...
              </>
            ) : 'Finalizar y Enviar Documentos'}
          </button>
        </div>

        <PrivacyNotice />
      </main>
    </div>
  );
};

