            <div className="bg-white border border-gray-100 rounded-lg p-3 min-h-[48px] flex items-center justify-between">
              <span className="text-xs md:text-sm font-medium text-navy truncate pr-4">
                {info.file ? info.file.name : 'Pendiente de adjuntar'}
              </span>
              <button
                onClick={handleBtnClick}
                className="shrink-0 px-3 md:px-4 py-1.5 bg-[#1d1c2d] text-white text-[9px] md:text-[10px] font-bold uppercase rounded-md hover:bg-opacity-90 transition-all tracking-widest shadow-sm"
              >
                {info.file ? 'Cambiar' : 'Seleccionar'}
              </button>
            </div>
          </div>
        </div>

        {info.error && (
          <div className="mt-4 p-3 bg-red-50 border border-red-100 rounded-lg flex items-center gap-2">
