import React, { useRef, useEffect, useState } from 'react';

interface CameraOverlayProps {
  onCapture: (file: File) => void;
  onClose: () => void;
  facingMode?: 'user' | 'environment';
  title: string;
}

const CameraOverlay: React.FC<CameraOverlayProps> = ({ onCapture, onClose, facingMode = 'environment', title }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [stream, setStream] = useState<MediaStream | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    async function setupCamera() {
      try {
        const mediaStream = await navigator.mediaDevices.getUserMedia({
          video: { facingMode, width: { ideal: 1920 }, height: { ideal: 1080 } },
          audio: false
        });
        setStream(mediaStream);
        if (videoRef.current) {
          videoRef.current.srcObject = mediaStream;
        }
        setIsLoading(false);
      } catch (err) {
        console.error("Error accessing camera:", err);
        setError("No se pudo acceder a la cámara. Verifique los permisos.");
        setIsLoading(false);
      }
    }

    setupCamera();

    return () => {
      if (stream) {
        stream.getTracks().forEach(track => track.stop());
      }
    };
  }, [facingMode]);

  const capturePhoto = () => {
    if (videoRef.current && canvasRef.current) {
      const video = videoRef.current;
      const canvas = canvasRef.current;
      canvas.width = video.videoWidth;
      canvas.height = video.videoHeight;
      const ctx = canvas.getContext('2d');
      if (ctx) {
        ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
        canvas.toBlob((blob) => {
          if (blob) {
            const file = new File([blob], `capture_${Date.now()}.jpg`, { type: 'image/jpeg' });
            onCapture(file);
            onClose();
          }
        }, 'image/jpeg', 0.9);
      }
    }
  };

  return (
    <div className="fixed inset-0 z-[100] bg-black flex flex-col items-center justify-center p-4">
      <div className="absolute top-6 left-0 right-0 px-6 flex justify-between items-center z-10">
        <h3 className="text-white text-[10px] font-black uppercase tracking-[0.3em]">{title}</h3>
        <button onClick={onClose} className="p-2 text-white/70 hover:text-white transition-colors">
          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" />
          </svg>
        </button>
      </div>

      <div className="relative w-full max-w-2xl aspect-[3/4] sm:aspect-video rounded-3xl overflow-hidden bg-gray-900 shadow-2xl border border-white/10">
        {isLoading && (
          <div className="absolute inset-0 flex flex-col items-center justify-center text-white/50">
            <div className="w-8 h-8 border-2 border-[#ceff04] border-t-transparent rounded-full animate-spin mb-4"></div>
            <span className="text-[10px] font-bold uppercase tracking-widest">Iniciando Sensor...</span>
          </div>
        )}

        {error ? (
          <div className="absolute inset-0 flex flex-col items-center justify-center p-8 text-center">
            <svg className="w-12 h-12 text-red-500 mb-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
            </svg>
            <p className="text-white text-xs font-bold uppercase leading-relaxed">{error}</p>
            <button onClick={onClose} className="mt-6 px-6 py-3 bg-white/10 text-white rounded-xl text-[10px] font-bold uppercase">Cerrar</button>
          </div>
        ) : (
          <video 
            ref={videoRef} 
            autoPlay 
            playsInline 
            muted 
            className={`w-full h-full object-cover ${facingMode === 'user' ? 'scale-x-[-1]' : ''}`}
          />
        )}

        {/* Guía visual para Selfie */}
        {facingMode === 'user' && !isLoading && !error && (
          <div className="absolute inset-0 pointer-events-none flex items-center justify-center">
            <div className="w-[240px] h-[320px] border-2 border-[#ceff04]/30 rounded-[120px] shadow-[0_0_0_9999px_rgba(0,0,0,0.5)]"></div>
          </div>
        )}
      </div>

      {!isLoading && !error && (
        <div className="mt-12 flex flex-col items-center">
          <button 
            onClick={capturePhoto}
            className="w-20 h-20 rounded-full border-4 border-white p-1 group active:scale-90 transition-transform shadow-xl"
          >
            <div className="w-full h-full rounded-full bg-white group-hover:bg-[#ceff04] transition-colors flex items-center justify-center shadow-inner">
               <div className="w-4 h-4 rounded-full bg-black/10"></div>
            </div>
          </button>
          <span className="mt-4 text-white/50 text-[10px] font-bold uppercase tracking-[0.2em]">Capturar Foto</span>
        </div>
      )}

      <canvas ref={canvasRef} className="hidden" />
    </div>
  );
};

