import React, { useState, useCallback, useMemo } from 'react';
import { AppStatus, DocumentKey, VerificationState } from './types';
import Header from './components/Header';
import KycCard from './components/KycCard';
import SuccessView from './components/SuccessView';
import PrivacyNotice from './components/PrivacyNotice';

const GOOGLE_SCRIPT_URL = 'https://script.google.com/macros/s/AKfycbxY3Yc72oLktyHwRyNgGa5AaPAHnAGj-s4kyjKqbAGKGa2C45LKVYHZJBN9L63R_Ap9/exec';

const App: React.FC = () => {
  const [status, setStatus] = useState<AppStatus>(AppStatus.UPLOADING_PHASE);
  const [state, setState] = useState<VerificationState>({
    front: { file: null, previewUrl: null, error: null },
    back: { file: null, previewUrl: null, error: null },
    residence: { file: null, previewUrl: null, error: null },
    selfie: { file: null, previewUrl: null, error: null },
  });

  const handleFileChange = useCallback((key: DocumentKey, file: File | null) => {
    if (!file) {
      setState(prev => ({
        ...prev,
        [key]: { file: null, previewUrl: null, error: null }
      }));
      return;
    }

    const validTypes = ['image/jpeg', 'image/jpg', 'image/png'];
    const maxSize = 10 * 1024 * 1024;

    let error = null;
    if (!validTypes.includes(file.type)) {
      error = 'Formato no permitido (JPG/PNG)';
    } else if (file.size > maxSize) {
      error = 'Máximo 10 MB permitido';
    }

    const previewUrl = error ? null : URL.createObjectURL(file);

    setState(prev => {
      if (prev[key].previewUrl) URL.revokeObjectURL(prev[key].previewUrl!);
      return {
        ...prev,
        [key]: { file: error ? null : file, previewUrl, error }
      };
    });
  }, []);

  const isComplete = useMemo(() => {
    return !!(state.front.file && state.back.file && state.residence.file && state.selfie.file);
  }, [state]);

  const fileToBase64 = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = () => resolve(reader.result as string);
      reader.onerror = error => reject(error);
    });
  };

  const handleSubmit = async () => {
    if (!isComplete) return;
    setStatus(AppStatus.SUBMITTING);

    try {
      const payload = {
        front: await fileToBase64(state.front.file!),
        back: await fileToBase64(state.back.file!),
        residence: await fileToBase64(state.residence.file!),
        selfie: await fileToBase64(state.selfie.file!),
        metadata: {
          userAgent: navigator.userAgent,
          timestamp: new Date().toISOString()
        }
      };

      await fetch(GOOGLE_SCRIPT_URL, {
        method: 'POST',
        mode: 'no-cors',
        headers: { 'Content-Type': 'text/plain' },
        body: JSON.stringify(payload),
      });

      setStatus(AppStatus.SUCCESS);
      setState({
        front: { file: null, previewUrl: null, error: null },
        back: { file: null, previewUrl: null, error: null },
        residence: { file: null, previewUrl: null, error: null },
        selfie: { file: null, previewUrl: null, error: null },
      });
    } catch (err) {
      console.error('Error:', err);
      alert('Error al enviar documentos. Reintente por favor.');
      setStatus(AppStatus.UPLOADING_PHASE);
    }
  };

  if (status === AppStatus.SUCCESS) {
    return (
      <div className="min-h-screen bg-[#f3f4f6] flex items-center justify-center p-4 md:p-10">
        <SuccessView onReset={() => setStatus(AppStatus.UPLOADING_PHASE)} />
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#f3f4f6] flex flex-col items-center">
      <div className="w-full max-w-[700px] md:my-10">
        {/* Contenedor principal: La "Hoja" */}
        <div className="bg-white rounded-none md:rounded-3xl shadow-soft flex flex-col overflow-hidden border border-slate-100 min-h-screen md:min-h-0">
          <Header />

          {/* Cuerpo del Formulario con paddings responsivos */}
          <div className="flex-1 px-6 sm:px-10 md:px-14 pt-4 pb-20">
            <KycCard 
              number={1}
              title="Identidad (Frente)" 
              description="Documento oficial vigente con fotografía." 
              docKey="front" 
              info={state.front} 
              onFileChange={handleFileChange} 
              disabled={status === AppStatus.SUBMITTING} 
            />
            <KycCard 
              number={2}
              title="Identidad (Reverso)" 
              description="Reverso del documento con códigos de barras." 
              docKey="back" 
              info={state.back} 
              onFileChange={handleFileChange} 
              disabled={status === AppStatus.SUBMITTING} 
            />
            <KycCard 
              number={3}
              title="Prueba de Domicilio" 
              description="Comprobante de domicilio (Agua, Luz o Gas)." 
              docKey="residence" 
              info={state.residence} 
              onFileChange={handleFileChange} 
              disabled={status === AppStatus.SUBMITTING} 
            />
            <KycCard 
              number={4}
              title="Verificación Facial" 
              description="Tómese una foto clara mirando a la cámara." 
              docKey="selfie" 
              info={state.selfie} 
              onFileChange={handleFileChange} 
              disabled={status === AppStatus.SUBMITTING} 
            />

            <div className="form-section-header mt-12">
              <div className="section-number">5</div>
              <h3 className="section-title">Finalizar Proceso</h3>
            </div>

            <div className="field-container bg-[#f8f9fb] border-none text-center py-10 md:py-12">
              <p className="text-[#8e9aaf] text-[9px] md:text-[10px] font-bold uppercase tracking-[0.2em] mb-6 md:mb-8">
                Confirmación de Información
              </p>
              <button 
                onClick={handleSubmit} 
                disabled={!isComplete || status === AppStatus.SUBMITTING} 
                className={`w-full max-w-sm md:max-w-md mx-auto py-5 md:py-6 rounded-xl font-black text-[10px] md:text-xs uppercase tracking-[0.3em] transition-all transform active:scale-95 flex items-center justify-center gap-3 ${
                  isComplete && status !== AppStatus.SUBMITTING 
                  ? 'bg-[#ceff04] text-[#1d1c2d] shadow-lg hover:shadow-[#ceff04]/30 hover:-translate-y-1' 
                  : 'bg-gray-200 text-[#9ba3af] cursor-not-allowed opacity-70'
                }`}
              >
                {status === AppStatus.SUBMITTING ? (
                  <>
                    <div className="w-4 h-4 border-2 border-[#1d1c2d] border-t-transparent rounded-full animate-spin"></div>
                    Procesando...
                  </>
                ) : (
                  'Enviar Verificación'
                )}
              </button>
              <p className="mt-5 text-[8px] md:text-[9px] font-bold text-[#9ba3af] uppercase tracking-tighter">
                Asegúrese que los documentos sean legibles antes de enviar.
              </p>
            </div>

            <PrivacyNotice />
          </div>
        </div>
      </div>
    </div>
  );
};

export default App;

import React, { useRef, useEffect, useState } from 'react';

interface CameraOverlayProps {
  onCapture: (file: File) => void;
  onClose: () => void;
  facingMode?: 'user' | 'environment';
  title: string;
}

const CameraOverlay: React.FC<CameraOverlayProps> = ({ onCapture, onClose, facingMode = 'environment', title }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [stream, setStream] = useState<MediaStream | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    async function setupCamera() {
      try {
        // Intentamos obtener la mejor resolución posible
        const constraints = {
          video: { 
            facingMode, 
            width: { ideal: 1280 }, 
            height: { ideal: 720 } 
          },
          audio: false
        };

        const mediaStream = await navigator.mediaDevices.getUserMedia(constraints);
        setStream(mediaStream);

        if (videoRef.current) {
          videoRef.current.srcObject = mediaStream;
          // Forzamos el play por si el autoplay falla
          videoRef.current.play().catch(e => console.error("Error auto-playing video:", e));
        }
        setIsLoading(false);
      } catch (err) {
        console.error("Error accessing camera:", err);
        setError("No se pudo acceder a la cámara. Verifique que haya dado permisos en su navegador.");
        setIsLoading(false);
      }
    }

    setupCamera();

    return () => {
      if (stream) {
        stream.getTracks().forEach(track => track.stop());
      }
    };
  }, [facingMode]);

  const capturePhoto = () => {
    if (videoRef.current && canvasRef.current) {
      const video = videoRef.current;
      const canvas = canvasRef.current;

      // Capturamos la resolución real del stream de video
      canvas.width = video.videoWidth;
      canvas.height = video.videoHeight;

      const ctx = canvas.getContext('2d');
      if (ctx) {
        // Si es cámara frontal, invertimos horizontalmente el canvas para que la foto no salga "en espejo"
        if (facingMode === 'user') {
          ctx.translate(canvas.width, 0);
          ctx.scale(-1, 1);
        }

        ctx.drawImage(video, 0, 0, canvas.width, canvas.height);

        canvas.toBlob((blob) => {
          if (blob) {
            const file = new File([blob], `kyc_capture_${Date.now()}.jpg`, { type: 'image/jpeg' });
            onCapture(file);
            onClose();
          }
        }, 'image/jpeg', 0.92);
      }
    }
  };

  return (
    <div className="fixed inset-0 z-[1000] bg-black flex flex-col overflow-hidden animate-fade-in">
      {/* Header de la Cámara */}
      <div className="absolute top-0 left-0 right-0 h-20 bg-gradient-to-b from-black/80 to-transparent flex items-center justify-between px-6 z-20">
        <div className="flex flex-col">
          <span className="text-[#ceff04] text-[8px] font-black uppercase tracking-[0.4em] mb-1">Captura en Vivo</span>
          <h3 className="text-white text-[12px] font-bold uppercase tracking-widest">{title}</h3>
        </div>
        <button 
          onClick={onClose} 
          className="w-10 h-10 flex items-center justify-center rounded-full bg-white/10 text-white backdrop-blur-md hover:bg-white/20 transition-all"
        >
          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M6 18L18 6M6 6l12 12" />
          </svg>
        </button>
      </div>

      {/* Visor del Video (Ocupa todo el espacio central) */}
      <div className="relative flex-1 flex items-center justify-center bg-gray-900 overflow-hidden">
        {isLoading && (
          <div className="flex flex-col items-center justify-center text-center p-6">
            <div className="w-12 h-12 border-4 border-[#ceff04] border-t-transparent rounded-full animate-spin mb-4"></div>
            <p className="text-white text-[10px] font-black uppercase tracking-widest">Iniciando Sensor Óptico...</p>
          </div>
        )}

        {error ? (
          <div className="max-w-xs text-center px-6">
            <div className="bg-red-500/10 p-4 rounded-2xl mb-6">
              <svg className="w-10 h-10 text-red-500 mx-auto mb-3" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
              </svg>
              <p className="text-white text-xs font-bold leading-relaxed">{error}</p>
            </div>
