              </div>
            ) : (
              // Guía Rectangular para Documentos
              <div className="w-[85vw] aspect-[1.58/1] max-w-[480px] border-[2px] border-white/40 rounded-3xl shadow-[0_0_0_2000px_rgba(0,0,0,0.7)] flex flex-col items-center justify-end pb-6">
                <span className="bg-white/10 backdrop-blur-md text-white border border-white/20 px-4 py-1.5 rounded-full text-[8px] font-black uppercase tracking-widest shadow-lg">Encuadre el Documento</span>
