import React, { useRef, useEffect, useState } from 'react';

interface CameraOverlayProps {
  onCapture: (file: File) => void;
  onClose: () => void;
  facingMode?: 'user' | 'environment';
  title: string;
}

const CameraOverlay: React.FC<CameraOverlayProps> = ({ onCapture, onClose, facingMode = 'environment', title }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [stream, setStream] = useState<MediaStream | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    async function setupCamera() {
      try {
        const constraints = {
          video: { 
            facingMode, 
            width: { ideal: 1920 }, 
            height: { ideal: 1080 } 
          },
          audio: false
        };

        const mediaStream = await navigator.mediaDevices.getUserMedia(constraints);
        setStream(mediaStream);

        if (videoRef.current) {
          videoRef.current.srcObject = mediaStream;
          // Forzamos la reproducción y nos aseguramos de que el video se visualice
          await videoRef.current.play();
        }
        setIsLoading(false);
      } catch (err) {
        console.error("Error accessing camera:", err);
        setError("Acceso denegado. Por favor, habilite los permisos de cámara en su navegador para continuar.");
        setIsLoading(false);
      }
    }

    setupCamera();

    return () => {
      if (stream) {
        stream.getTracks().forEach(track => track.stop());
      }
    };
  }, [facingMode]);

  const capturePhoto = () => {
    if (videoRef.current && canvasRef.current) {
      const video = videoRef.current;
      const canvas = canvasRef.current;

      canvas.width = video.videoWidth;
      canvas.height = video.videoHeight;

      const ctx = canvas.getContext('2d');
      if (ctx) {
        if (facingMode === 'user') {
          ctx.translate(canvas.width, 0);
          ctx.scale(-1, 1);
        }
        ctx.drawImage(video, 0, 0, canvas.width, canvas.height);

        canvas.toBlob((blob) => {
          if (blob) {
            const file = new File([blob], `kyc_capture_${Date.now()}.jpg`, { type: 'image/jpeg' });
            onCapture(file);
            onClose();
          }
        }, 'image/jpeg', 0.95);
      }
    }
  };

  return (
    // Usamos h-[100dvh] para garantizar pantalla completa real en móviles
    <div className="fixed inset-0 z-[1000] bg-black flex flex-col h-[100dvh] w-screen overflow-hidden animate-fade-in">

      {/* Header flotante: Minimalista para no obstruir */}
      <div className="absolute top-0 left-0 right-0 h-24 bg-gradient-to-b from-black/90 via-black/40 to-transparent flex items-start justify-between px-6 pt-8 z-30">
        <div className="flex flex-col">
          <span className="text-[#ceff04] text-[7px] font-black uppercase tracking-[0.4em] mb-1">Sistema de Verificación Óptica</span>
          <h3 className="text-white text-[11px] font-bold uppercase tracking-[0.2em] opacity-90">{title}</h3>
        </div>
        <button 
          onClick={onClose} 
          className="w-10 h-10 flex items-center justify-center rounded-full bg-white/10 text-white backdrop-blur-xl border border-white/10 hover:bg-white/20 active:scale-90 transition-all"
        >
          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M6 18L18 6M6 6l12 12" />
          </svg>
        </button>
      </div>

      {/* Contenedor del Video: Forzamos expansión total */}
      <div className="relative flex-1 w-full bg-[#0a0a0f] flex items-center justify-center overflow-hidden">
        {isLoading && (
          <div className="flex flex-col items-center z-20">
            <div className="w-10 h-10 border-3 border-[#ceff04] border-t-transparent rounded-full animate-spin mb-4"></div>
            <p className="text-white/40 text-[9px] font-black uppercase tracking-[0.3em]">Calibrando Sensor...</p>
          </div>
        )}

        {error ? (
          <div className="z-20 max-w-xs text-center px-8">
            <div className="bg-red-500/10 border border-red-500/20 p-6 rounded-3xl mb-8 backdrop-blur-md">
              <svg className="w-12 h-12 text-red-500 mx-auto mb-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="1.5" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
              </svg>
              <p className="text-white text-[10px] font-bold uppercase leading-relaxed tracking-wider">{error}</p>
            </div>
            <button 
              onClick={onClose} 
              className="w-full py-4 bg-white text-black rounded-2xl font-black text-[10px] uppercase tracking-[0.2em] shadow-xl"
            >
              Cerrar y Reintentar
            </button>
          </div>
        ) : (
          <video 
            ref={videoRef} 
            autoPlay 
            playsInline 
            muted 
            className={`absolute inset-0 w-full h-full object-cover ${facingMode === 'user' ? 'scale-x-[-1]' : ''}`}
          />
        )}

        {/* Máscara de Guía de Encuadre */}
        {!isLoading && !error && (
          <div className="absolute inset-0 pointer-events-none flex flex-col items-center justify-center z-10">
            {facingMode === 'user' ? (
              // Guía Ovalada para Selfie
              <div className="w-[75vw] h-[90vw] max-w-[280px] max-h-[360px] border-[2px] border-[#ceff04] rounded-[140px] shadow-[0_0_0_2000px_rgba(0,0,0,0.7)] flex flex-col items-center justify-end pb-8">
                <span className="bg-[#ceff04] text-[#1d1c2d] px-4 py-1.5 rounded-full text-[8px] font-black uppercase tracking-widest shadow-lg">Posicione su Rostro</span>
              </div>
            ) : (
              // Guía Rectangular para Documentos
              <div className="w-[85vw] aspect-[1.58/1] max-w-[480px] border-[2px] border-white/40 rounded-3xl shadow-[0_0_0_2000px_rgba(0,0,0,0.7)] flex flex-col items-center justify-end pb-6">
                <span className="bg-white/10 backdrop-blur-md text-white border border-white/20 px-4 py-1.5 rounded-full text-[8px] font-black uppercase tracking-widest shadow-lg">Encuadre el Documento</span>
              </div>
            )}
          </div>
        )}
      </div>

      {/* Controles Inferiores Estilo Cámara Profesional */}
      <div className="h-40 bg-black flex flex-col items-center justify-center px-10 relative z-30">
        {!isLoading && !error && (
          <div className="flex items-center justify-center w-full max-w-sm">
            {/* Botón Obturador */}
            <div className="flex flex-col items-center gap-3">
              <button 
                onClick={capturePhoto}
                className="w-20 h-20 rounded-full border-[4px] border-white/20 p-1 flex items-center justify-center group active:scale-90 transition-all duration-75"
              >
                <div className="w-full h-full rounded-full bg-white group-hover:bg-[#ceff04] shadow-2xl transition-colors"></div>
              </button>
              <span className="text-white/30 text-[8px] font-bold uppercase tracking-[0.4em]">Capturar Foto</span>
            </div>
