import React, { useRef, useState } from 'react';
import { DocumentInfo, DocumentKey } from '../types';
// Update to named import to match CameraOverlay.tsx
import { CameraOverlay } from './CameraOverlay';

interface KycCardProps {
  number: number;
  title: string;
  description: string;
  docKey: DocumentKey;
  info: DocumentInfo;
  onFileChange: (key: DocumentKey, file: File | null) => void;
  disabled?: boolean;
}

const KycCard: React.FC<KycCardProps> = ({ number, title, docKey, info, onFileChange, disabled }) => {
  const inputRef = useRef<HTMLInputElement>(null);
  const [isCameraOpen, setIsCameraOpen] = useState(false);

  const handleBtnClick = () => {
    inputRef.current?.click();
  };

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0] || null;
    onFileChange(docKey, file);
  };

  const handleCameraCapture = (file: File) => {
    onFileChange(docKey, file);
  };

  return (
    <div className={`mb-8 md:mb-10 animate-slide-up ${disabled ? 'opacity-50 pointer-events-none' : ''}`} style={{ animationDelay: `${number * 0.1}s` }}>
      <div className="form-section-header">
        <div className="section-number">{number}</div>
        <h3 className="section-title text-[12px] md:text-[14px]">{title}</h3>
      </div>

      <div className="field-container group">
        <div className="flex flex-col sm:flex-row items-center gap-6">
          {/* Preview Area */}
          <div 
            onClick={() => !info.previewUrl && setIsCameraOpen(true)}
            className={`cursor-pointer relative w-full sm:w-32 h-32 md:w-40 md:h-24 rounded-xl border-2 border-dashed transition-all flex items-center justify-center shrink-0 overflow-hidden ${
              info.previewUrl 
                ? 'border-[#ceff04] bg-white' 
                : 'border-gray-200 bg-gray-50 hover:bg-white hover:border-gray-400'
            }`}
          >
            {info.previewUrl ? (
              <img 
                src={info.previewUrl} 
                alt="Documento" 
                className="w-full h-full object-cover" 
              />
            ) : (
              <div className="flex flex-col items-center text-gray-400">
                <svg className="w-8 h-8 mb-1" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="1.5" d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z" />
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="1.5" d="M15 13a3 3 0 11-6 0 3 3 0 016 0z" />
                </svg>
                <span className="text-[10px] font-bold uppercase">Cámara</span>
              </div>
            )}

            {info.file && !info.error && (
              <div className="absolute top-2 right-2 bg-[#ceff04] text-[#1d1c2d] p-1 rounded-full shadow-md">
                <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M5 13l4 4L19 7" />
                </svg>
              </div>
            )}
          </div>

          <div className="flex-1 w-full text-center sm:text-left">
            <label className="block text-[10px] md:text-[11px] font-bold text-gray-400 uppercase mb-2 tracking-wider">
              {info.file ? 'Archivo cargado' : 'Estado del documento'}
            </label>
            <div className="bg-white border border-gray-100 rounded-lg p-2 md:p-3 min-h-[48px] flex items-center justify-between gap-2">
              <span className="text-[10px] md:text-sm font-medium text-navy truncate pr-2">
                {info.file ? info.file.name : 'Pendiente'}
              </span>
              <div className="flex gap-2 shrink-0">
                <button
                  onClick={() => setIsCameraOpen(true)}
                  className="p-2 bg-[#f4f7fa] text-[#1d1c2d] rounded-md hover:bg-gray-200 transition-all shadow-sm border border-gray-100"
                  title="Tomar Foto"
                >
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z" />
                  </svg>
                </button>
                <button
                  onClick={handleBtnClick}
                  className="px-3 md:px-4 py-1.5 bg-[#1d1c2d] text-white text-[9px] md:text-[10px] font-bold uppercase rounded-md hover:bg-opacity-90 transition-all tracking-widest shadow-sm"
                >
                  {info.file ? 'Cambiar' : 'Archivo'}
                </button>
              </div>
            </div>
          </div>
        </div>

        {info.error && (
          <div className="mt-4 p-3 bg-red-50 border border-red-100 rounded-lg flex items-center gap-2">
            <svg className="w-4 h-4 text-red-500" fill="currentColor" viewBox="0 0 20 20">
              <path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7 4a1 1 0 11-2 0 1 1 0 012 0zm-1-9a1 1 0 00-1 1v4a1 1 0 102 0V6a1 1 0 00-1-1z" clipRule="evenodd" />
            </svg>
            <p className="text-red-600 text-[10px] md:text-[11px] font-bold uppercase">{info.error}</p>
          </div>
        )}
      </div>

      <input
        type="file"
        ref={inputRef}
        onChange={handleInputChange}
        accept=".jpg,.jpeg,.png"
        className="hidden"
      />

      {isCameraOpen && (
        <CameraOverlay 
          title={title}
          onCapture={handleCameraCapture}
          onClose={() => setIsCameraOpen(false)}
          facingMode={docKey === 'selfie' ? 'user' : 'environment'}
        />
      )}
    </div>
  );
};

