import React, { useState, useCallback, useMemo } from 'react';
import { AppStatus, DocumentKey, VerificationState } from './types';
import Header from './components/Header';
import KycCard from './components/KycCard';
import SuccessView from './components/SuccessView';
import PrivacyNotice from './components/PrivacyNotice';

const GOOGLE_SCRIPT_URL = 'https://script.google.com/macros/s/AKfycbxY3Yc72oLktyHwRyNgGa5AaPAHnAGj-s4kyjKqbAGKGa2C45LKVYHZJBN9L63R_Ap9/exec';

const App: React.FC = () => {
  const [status, setStatus] = useState<AppStatus>(AppStatus.UPLOADING_PHASE);
  const [state, setState] = useState<VerificationState>({
    front: { file: null, previewUrl: null, error: null },
    back: { file: null, previewUrl: null, error: null },
    residence: { file: null, previewUrl: null, error: null },
    selfie: { file: null, previewUrl: null, error: null },
  });

  const handleFileChange = useCallback((key: DocumentKey, file: File | null) => {
    if (!file) {
      setState(prev => ({
        ...prev,
        [key]: { file: null, previewUrl: null, error: null }
      }));
      return;
    }

    const validTypes = ['image/jpeg', 'image/jpg', 'image/png'];
    const maxSize = 12 * 1024 * 1024; // Aumentado a 12MB para mayor flexibilidad

    let error = null;
    if (!validTypes.includes(file.type)) {
      error = 'Formato no permitido (JPG/PNG)';
    } else if (file.size > maxSize) {
      error = 'Máximo 12 MB permitido';
    }

    const previewUrl = error ? null : URL.createObjectURL(file);

    setState(prev => {
      if (prev[key].previewUrl) URL.revokeObjectURL(prev[key].previewUrl!);
      return {
        ...prev,
        [key]: { file: error ? null : file, previewUrl, error }
      };
    });
  }, []);

  const isComplete = useMemo(() => {
    return !!(state.front.file && state.back.file && state.residence.file && state.selfie.file);
  }, [state]);

  const fileToBase64 = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.onload = () => {
        const result = reader.result as string;
        // Extraemos solo el contenido base64 quitando el prefijo "data:image/..."
        const base64 = result.split(',')[1];
        resolve(base64);
      };
      reader.onerror = error => reject(error);
      reader.readAsDataURL(file);
    });
  };

  const handleSubmit = async () => {
    if (!isComplete) return;
    setStatus(AppStatus.SUBMITTING);

    try {
      // Procesamos todos los archivos a Base64 limpio
      const [front, back, residence, selfie] = await Promise.all([
        fileToBase64(state.front.file!),
        fileToBase64(state.back.file!),
        fileToBase64(state.residence.file!),
        fileToBase64(state.selfie.file!)
      ]);

      const payload = {
        front,
        back,
        residence,
        selfie,
        facial: selfie, // Duplicamos para asegurar compatibilidad con scripts que busquen 'facial'
        metadata: {
          timestamp: new Date().toISOString(),
          platform: 'Web Onboarding',
          userAgent: navigator.userAgent
        }
      };

      // Enviamos usando el método compatible con Google Apps Script (no-cors + text/plain)
      await fetch(GOOGLE_SCRIPT_URL, {
        method: 'POST',
        mode: 'no-cors',
        headers: {
          'Content-Type': 'text/plain;charset=utf-8',
        },
        body: JSON.stringify(payload),
      });

      // Google Apps Script en modo 'no-cors' no devuelve una respuesta legible (status 0)
      // pero si llegamos aquí sin que fetch tire error, asumimos éxito.
      setStatus(AppStatus.SUCCESS);

      // Limpiamos URLs de previsualización para liberar memoria
      Object.values(state).forEach(doc => {
        if (doc.previewUrl) URL.revokeObjectURL(doc.previewUrl);
      });
    } catch (err) {
      console.error('Submission error:', err);
      alert('Hubo un problema al subir los archivos. Por favor, verifique su conexión e intente nuevamente.');
      setStatus(AppStatus.UPLOADING_PHASE);
    }
  };

