            <KycCard 
              number={2}
              title="Identidad (Reverso)" 
              description="Parte trasera de su identificación oficial." 
              docKey="back" 
              info={state.back} 
              onFileChange={handleFileChange} 
              disabled={status === AppStatus.SUBMITTING} 
            />
            <KycCard 
              number={3}
              title="Prueba de Domicilio" 
