  if (status === AppStatus.SUCCESS) {
    return (
      <div className="min-h-screen bg-[#f3f4f6] flex items-center justify-center p-4 md:p-10">
        <SuccessView onReset={() => setStatus(AppStatus.UPLOADING_PHASE)} />
      </div>
    );
