  const [alignment, setAlignment] = useState<AlignmentStatus>('neutral');
  const [feedback, setFeedback] = useState<string>('Buscando documento...');

  // Referencia para evitar colisiones de análisis
  const isAnalyzing = useRef(false);

  useEffect(() => {
    async function setupCamera() {
      try {
        const constraints = {
          video: { 
            facingMode, 
            width: { ideal: 1920 }, 
            height: { ideal: 1080 } 
          },
          audio: false
        };

        const mediaStream = await navigator.mediaDevices.getUserMedia(constraints);
        setStream(mediaStream);

        if (videoRef.current) {
          videoRef.current.srcObject = mediaStream;
          await videoRef.current.play();
        }
        setIsLoading(false);
      } catch (err) {
        console.error("Error accessing camera:", err);
        setError("Acceso denegado. Por favor, habilite los permisos de cámara.");
        setIsLoading(false);
      }
    }

    setupCamera();

    return () => {
      if (stream) {
        stream.getTracks().forEach(track => track.stop());
      }
    };
  }, [facingMode]);

  // Ciclo de análisis con Gemini
  useEffect(() => {
    if (isLoading || error || !stream) return;

    const analyzeFrame = async () => {
      if (isAnalyzing.current || !videoRef.current || !canvasRef.current) return;

      isAnalyzing.current = true;
      setAlignment('scanning');

      try {
        const video = videoRef.current;
        const canvas = canvasRef.current;
        const ctx = canvas.getContext('2d');

        // Capturar frame pequeño para rapidez
        canvas.width = 320;
        canvas.height = 240;
        if (ctx) {
          ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
          const base64Data = canvas.toDataURL('image/jpeg', 0.5).split(',')[1];

          const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
          const prompt = `Analyze this frame for a KYC process. The user is trying to capture: ${title}. 
          Return ONLY a JSON with: 
          "status": ("good" if centered/clear, "poor" if too far/near/blurry/not found), 
          "message": (short instruction in Spanish like "Acerque más", "Céntrelo", "¡Perfecto!").`;

          const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: {
              parts: [
                { inlineData: { data: base64Data, mimeType: 'image/jpeg' } },
                { text: prompt }
              ]
            },
            config: { responseMimeType: "application/json" }
          });

          const result = JSON.parse(response.text || '{}');
          setAlignment(result.status || 'neutral');
          setFeedback(result.message || 'Escaneando...');
        }
      } catch (e) {
        console.error("Analysis error:", e);
      } finally {
        isAnalyzing.current = false;
      }
    };

    const interval = setInterval(analyzeFrame, 2000);
    return () => clearInterval(interval);
  }, [isLoading, error, stream, title]);

  const capturePhoto = () => {
    if (videoRef.current && canvasRef.current) {
      const video = videoRef.current;
      const canvas = canvasRef.current;

      canvas.width = video.videoWidth;
      canvas.height = video.videoHeight;

      const ctx = canvas.getContext('2d');
      if (ctx) {
        if (facingMode === 'user') {
          ctx.translate(canvas.width, 0);
          ctx.scale(-1, 1);
        }
        ctx.drawImage(video, 0, 0, canvas.width, canvas.height);

        canvas.toBlob((blob) => {
          if (blob) {
            const file = new File([blob], `kyc_capture_${Date.now()}.jpg`, { type: 'image/jpeg' });
            onCapture(file);
            onClose();
          }
        }, 'image/jpeg', 0.95);
      }
    }
  };

  const getGuideColor = () => {
    switch(alignment) {
      case 'good': return 'border-[#ceff04] shadow-[0_0_40px_rgba(206,255,4,0.5)]';
      case 'poor': return 'border-red-500 animate-pulse';
      case 'scanning': return 'border-blue-400 opacity-60';
      default: return 'border-white/40';
    }
  };

  const renderFramingGuide = () => {
    if (isLoading || error) return null;

    let guideStyle = "";
    if (docKey === 'selfie') {
      guideStyle = "w-[80vw] h-[100vw] max-w-[300px] max-h-[380px] rounded-[160px]";
    } else if (docKey === 'residence') {
      guideStyle = "w-[80vw] h-[110vw] max-w-[400px] max-h-[550px] rounded-[20px]";
    } else {
      guideStyle = "w-[88vw] aspect-[1.58/1] max-w-[500px] rounded-[40px]";
    }

    return (
      <div className={`${guideStyle} border-[3px] transition-all duration-500 shadow-[0_0_0_9999px_rgba(0,0,0,0.75)] flex flex-col items-center justify-end pb-8 ${getGuideColor()}`}>
        <div className={`backdrop-blur-md border px-6 py-2 rounded-full text-[9px] font-black uppercase tracking-[0.2em] shadow-2xl transition-colors duration-300 ${
          alignment === 'good' ? 'bg-[#ceff04] text-[#1d1c2d] border-[#ceff04]' : 'bg-white/10 text-white border-white/20'
        }`}>
          {feedback}
        </div>
        {alignment === 'scanning' && (
           <div className="absolute inset-0 overflow-hidden pointer-events-none rounded-[inherit]">
             <div className="w-full h-[2px] bg-blue-400/50 absolute top-0 animate-[scan_2s_infinite]"></div>
           </div>
        )}
      </div>
    );
  };

  return createPortal(
    <div className="fixed inset-0 z-[9999] bg-black flex flex-col h-[100dvh] w-screen overflow-hidden animate-fade-in">
      <style>{`
        @keyframes scan {
          0% { transform: translateY(0); opacity: 0; }
          50% { opacity: 1; }
          100% { transform: translateY(100%); opacity: 0; }
        }
      `}</style>

      <div className="absolute top-0 left-0 right-0 h-32 bg-gradient-to-b from-black via-black/40 to-transparent flex items-start justify-between px-8 pt-10 z-30">
        <div className="flex flex-col">
          <div className="flex items-center gap-2 mb-1.5">
            <div className={`w-1.5 h-1.5 rounded-full animate-pulse ${alignment === 'good' ? 'bg-[#ceff04]' : 'bg-blue-400'}`}></div>
            <span className="text-white/60 text-[8px] font-black uppercase tracking-[0.4em]">Visión Artificial Activa</span>
          </div>
          <h3 className="text-white text-[13px] font-bold uppercase tracking-[0.1em]">{title}</h3>
        </div>

        <button onClick={onClose} className="w-12 h-12 flex items-center justify-center rounded-full bg-white/10 text-white backdrop-blur-2xl border border-white/20 active:scale-90 transition-all">
          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M6 18L18 6M6 6l12 12" />
          </svg>
        </button>
      </div>

      <div className="relative flex-1 w-full bg-[#050508] flex items-center justify-center overflow-hidden">
        {isLoading ? (
          <div className="flex flex-col items-center z-20">
            <div className="w-12 h-12 border-[3px] border-[#ceff04] border-t-transparent rounded-full animate-spin mb-6"></div>
            <p className="text-white/40 text-[10px] font-black uppercase tracking-[0.5em]">Calibrando Sensor</p>
          </div>
        ) : error ? (
          <div className="z-20 text-center px-10">
            <p className="text-white text-[11px] font-bold uppercase tracking-widest">{error}</p>
          </div>
        ) : (
          <video ref={videoRef} autoPlay playsInline muted className={`absolute inset-0 w-full h-full object-cover transition-opacity duration-700 ${facingMode === 'user' ? 'scale-x-[-1]' : ''}`} />
        )}

        <div className="absolute inset-0 pointer-events-none flex flex-col items-center justify-center z-10">
          {renderFramingGuide()}
        </div>
      </div>

      <div className="h-44 bg-black flex flex-col items-center justify-center px-10 relative z-30 border-t border-white/5">
        {!isLoading && !error && (
          <div className="flex flex-col items-center gap-5">
            <button 
              onClick={capturePhoto}
              className={`w-24 h-24 rounded-full border-[6px] p-2 flex items-center justify-center group active:scale-90 transition-all duration-300 ${
                alignment === 'good' ? 'border-[#ceff04]/30' : 'border-white/10'
              }`}
            >
              <div className={`w-full h-full rounded-full transition-all duration-300 ${
                alignment === 'good' ? 'bg-[#ceff04] shadow-[0_0_30px_#ceff04]' : 'bg-white'
              }`}></div>
            </button>
            <span className={`text-[9px] font-black uppercase tracking-[0.5em] transition-colors ${
              alignment === 'good' ? 'text-[#ceff04]' : 'text-white/20'
            }`}>
              {alignment === 'good' ? 'Captura Recomendada' : 'Alineando Documento'}
            </span>
          </div>
        )}
      </div>

      <canvas ref={canvasRef} className="hidden" />
    </div>,
    document.body
  );
};

